// tsconfig.json üçün qeyd: {"experimentalDecorators": true}

// 1. Sadə Metod Dekoratoru
function logMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log("Method " + propertyKey + " called with args: " + args);
    return originalMethod.apply(this, args);
  };
}
class Calculator {
  @logMethod
  add(a: number, b: number): number {
    return a + b;
  }
}
const calc = new Calculator();
console.log(calc.add(5, 3)); // Çıxış: Method add called with args: 5,3
// Çıxış: 8

// 2. Dekorator Fabriki
function logWithPrefix(prefix: string) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;
    descriptor.value = function (...args: any[]) {
      console.log(prefix + " " + propertyKey + " called with: " + args);
      return originalMethod.apply(this, args);
    };
  };
}
class Greeter {
  @logWithPrefix("INFO")
  greet(name: string): string {
    return "Hello, " + name;
  }
}
const greeter = new Greeter();
console.log(greeter.greet("Alice")); // Çıxış: INFO greet called with: Alice
// Çıxış: Hello, Alice

// 3. Metodun Nəticəsini Dəyişdirən Dekorator
function doubleResult(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    const result = originalMethod.apply(this, args);
    return result * 2;
  };
}
class MathUtils {
  @doubleResult
  multiply(a: number, b: number): number {
    return a * b;
  }
}
const math = new MathUtils();
console.log(math.multiply(4, 5)); // Çıxış: 40 (4 * 5 * 2)

// 4. Digər Dekoratorlarla Birləşmə
function logClass(prefix: string) {
  return function (constructor: Function) {
    console.log(prefix + " class created: " + constructor.name);
  };
}
@logClass("Store")
class Store {
  @logMethod
  addItem(item: string): string {
    return "Added " + item;
  }
}
const store = new Store();
console.log(store.addItem("Book")); // Çıxış: Store class created: Store
// Çıxış: Method addItem called with args: Book
// Çıxış: Added Book

// Mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

function logAccess(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Accessing ${propertyKey} with args: ${JSON.stringify(args)}`);
    return originalMethod.apply(this, args);
  };
}

class Store {
  products: Product[] = [];

  @logAccess
  addProduct(product: Product): Product[] {
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
const laptop: Product = { id: "P001", name: "Laptop", price: 999 };
store.addProduct(laptop);
// Çıxış: Accessing addProduct with args: [{"id":"P001","name":"Laptop","price":999}]
console.log(store.products); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]

